import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { profileAPI, mentorsAPI, quizAPI } from '../../services/api';
import './Progress.css';

const Progress = () => {
  const [progress, setProgress] = useState({
    quizCompleted: 0,
    profileCompleted: 0,
    skillsAdded: 0,
    mentorsConnected: 0,
    coursesEnrolled: 0
  });
  const [quizResults, setQuizResults] = useState(null);
  const [loading, setLoading] = useState(true);
  const [lastUpdated, setLastUpdated] = useState(null);
  const [dataVersion, setDataVersion] = useState(0);
  const { user } = useAuth();

  // Real-time progress tracking
  useEffect(() => {
    fetchProgress();
    
    const interval = setInterval(fetchProgress, 60000);
    return () => clearInterval(interval);
  }, [user, dataVersion]);

  const fetchProgress = async () => {
    try {
      console.log('🔄 Fetching progress data...');
      setLoading(true);
      
      const [profileResponse, mentorResponse, quizResponse] = await Promise.allSettled([
        profileAPI.getProfile(),
        mentorsAPI.getMyRequests(),
        quizAPI.getHistory()
      ]);

      console.log('📊 API Responses Status:', {
        profile: profileResponse.status,
        mentor: mentorResponse.status,
        quiz: quizResponse.status
      });

      let quizCompleted = 0;
      let profileCompleted = 0;
      let skillsAdded = 0;
      let mentorsConnected = 0;
      let quizData = null;

      // 1. Check Quiz Completion - STRICT checking
      const quizCheck = await checkQuizCompletion(quizResponse, user);
      quizCompleted = quizCheck.completed ? 100 : 0;
      quizData = quizCheck.results;
      setQuizResults(quizData);
      console.log('✅ Quiz Completion Status:', quizCompleted, 'Has Results:', !!quizData);

      // 2. Check Profile Completion
      const profileData = await getProfileData(profileResponse, user);
      profileCompleted = calculateProfileCompletion(profileData);
      skillsAdded = calculateSkillsProgress(profileData.skills || []);
      console.log('✅ Profile Completion:', profileCompleted);

      // 3. Check Mentor Connections
      mentorsConnected = await checkMentorConnections(mentorResponse);
      console.log('✅ Mentor Connections:', mentorsConnected);

      const progressData = {
        quizCompleted,
        profileCompleted,
        skillsAdded,
        mentorsConnected,
        coursesEnrolled: 0
      };
      
      console.log('🎯 Final Progress Data:', progressData);
      setProgress(progressData);
      setLastUpdated(new Date());
      
    } catch (error) {
      console.error('❌ Error in fetchProgress:', error);
      const fallbackProgress = calculateStableProgress(user);
      setProgress(fallbackProgress);
    } finally {
      setLoading(false);
    }
  };

  // STRICT quiz completion check - Only mark as complete if we have actual results
  const checkQuizCompletion = async (quizResponse, userData) => {
    try {
      let results = null;
      let completed = false;

      // Method 1: Check quiz history API for valid results
      if (quizResponse.status === 'fulfilled' && quizResponse.value.success) {
        const quizHistory = quizResponse.value.history || [];
        if (quizHistory.length > 0) {
          // Get the most recent quiz result
          const latestQuiz = quizHistory[0];
          // Only mark as completed if we have actual results data
          if (latestQuiz.results && latestQuiz.results.personalityType) {
            results = latestQuiz.results;
            completed = true;
            console.log('📝 Quiz completed (from history API with valid results)');
          }
        }
      }

      // Method 2: Check user quiz results directly - STRICT check
      if (!completed && userData?.quizResults?.length > 0) {
        const userQuiz = userData.quizResults[0];
        // Only mark as completed if we have valid results
        if (userQuiz.personalityType || userQuiz.careerRecommendations) {
          results = userQuiz;
          completed = true;
          console.log('📝 Quiz completed (from user data with valid results)');
        }
      }

      // Method 3: Check localStorage for valid quiz results
      if (!completed) {
        const localQuizResults = localStorage.getItem('last_quiz_results');
        const localQuizTime = localStorage.getItem('last_quiz_time');
        
        if (localQuizResults && localQuizTime) {
          try {
            const parsedResults = JSON.parse(localQuizResults);
            // Only mark as completed if we have valid results data
            if (parsedResults.personalityType || parsedResults.careerRecommendations) {
              // Check if quiz was taken recently (within last 30 days)
              const quizDate = new Date(localQuizTime);
              const thirtyDaysAgo = new Date();
              thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
              
              if (quizDate > thirtyDaysAgo) {
                results = parsedResults;
                completed = true;
                console.log('📝 Quiz completed (from localStorage with valid results)');
              }
            }
          } catch (e) {
            console.log('❌ Invalid quiz results in localStorage');
          }
        }
      }

      // Method 4: Check completion flags - ONLY if we also have results
      if (!completed) {
        const quizCompleted = localStorage.getItem('quiz_completed');
        const quizTaken = localStorage.getItem('quiz_taken');
        const hasResults = localStorage.getItem('last_quiz_results');
        
        // Only mark as completed if BOTH flag is true AND we have results
        if ((quizCompleted === 'true' || quizTaken === 'true') && hasResults) {
          try {
            const parsedResults = JSON.parse(hasResults);
            if (parsedResults.personalityType) {
              completed = true;
              results = parsedResults;
              console.log('📝 Quiz completed (from flags with results)');
            }
          } catch (e) {
            console.log('❌ Invalid results with completion flags');
          }
        }
      }

      console.log('📝 Final Quiz Check - Completed:', completed, 'Has Results:', !!results);
      return { completed, results };
    } catch (error) {
      console.error('❌ Error checking quiz completion:', error);
      // Fallback: only mark as completed if user has valid quiz results
      const hasValidQuizResults = userData?.quizResults?.some(quiz => 
        quiz.personalityType || quiz.careerRecommendations
      );
      return { 
        completed: hasValidQuizResults, 
        results: hasValidQuizResults ? userData.quizResults[0] : null 
      };
    }
  };

  // Stable profile data fetching
  const getProfileData = async (profileResponse, userData) => {
    if (profileResponse.status === 'fulfilled' && profileResponse.value?.user) {
      return profileResponse.value.user.profile || {};
    }
    return userData?.profile || {};
  };

  // Stable mentor connections check
  const checkMentorConnections = async (mentorResponse) => {
    try {
      if (mentorResponse.status === 'fulfilled' && mentorResponse.value.success) {
        const acceptedMentors = mentorResponse.value.requests?.filter(
          req => req.status === 'accepted'
        ).length || 0;
        return Math.min((acceptedMentors / 3) * 100, 100);
      }
      return 0;
    } catch (error) {
      console.error('❌ Error checking mentor connections:', error);
      return 0;
    }
  };

  // Stable progress calculation fallback
  const calculateStableProgress = (userData) => {
    // STRICT check for quiz completion
    const hasValidQuizResults = userData?.quizResults?.some(quiz => 
      quiz.personalityType || quiz.careerRecommendations
    );
    const quizCompleted = hasValidQuizResults ? 100 : 0;
    
    const profileCompleted = calculateProfileCompletion(userData?.profile || {});
    const skillsAdded = calculateSkillsProgress(userData?.profile?.skills || []);
    
    console.log('🛡️ Using stable fallback progress:', {
      quizCompleted,
      profileCompleted,
      skillsAdded
    });
    
    return {
      quizCompleted,
      profileCompleted,
      skillsAdded,
      mentorsConnected: 0,
      coursesEnrolled: 0
    };
  };

  const calculateProfileCompletion = (profile) => {
    if (!profile) return 0;
    
    const completionCriteria = [
      { key: 'bio', weight: 20, check: (val) => val && val.trim().length > 10 },
      { key: 'education', weight: 20, check: (val) => val && val.trim().length > 0 },
      { key: 'experience', weight: 20, check: (val) => val !== undefined && val !== null && val !== '' },
      { key: 'skills', weight: 20, check: (val) => val && val.length > 0 },
      { key: 'interests', weight: 20, check: (val) => val && val.length > 0 }
    ];

    let totalScore = 0;
    completionCriteria.forEach(criteria => {
      if (criteria.check(profile[criteria.key])) {
        totalScore += criteria.weight;
      }
    });

    return totalScore;
  };

  const calculateSkillsProgress = (skills) => {
    const skillsCount = skills.length;
    return Math.min((skillsCount / 5) * 100, 100);
  };

  const getOverallProgress = () => {
    const values = Object.values(progress);
    const overall = Math.round(values.reduce((a, b) => a + b, 0) / values.length);
    return overall;
  };

  const getProgressColor = (percentage) => {
    if (percentage >= 80) return '#10b981';
    if (percentage >= 50) return '#f59e0b';
    return '#ef4444';
  };

  const refreshProgress = () => {
    console.log('🔄 Manual refresh triggered');
    setDataVersion(prev => prev + 1);
  };

  // Debug function to simulate quiz completion (for testing only)
  const simulateQuizCompletion = () => {
    console.log('🧪 Simulating quiz completion with sample results');
    
    const sampleResults = {
      personalityType: 'Analytical Innovator',
      careerRecommendations: [
        {
          field: 'Technology',
          role: 'Software Engineer',
          matchPercentage: 95,
          description: 'Develop innovative software solutions and applications',
          skillsRequired: ['Programming', 'Problem Solving', 'Algorithms'],
          growthProspects: 'High demand with excellent career progression'
        }
      ],
      strengths: ['Analytical Thinking', 'Problem Solving', 'Attention to Detail'],
      areasForDevelopment: ['Public Speaking', 'Team Collaboration'],
      suggestedSkills: ['Python', 'Data Analysis', 'Machine Learning'],
      compatibilityScore: 85
    };
    
    // Save to localStorage
    localStorage.setItem('last_quiz_results', JSON.stringify(sampleResults));
    localStorage.setItem('last_quiz_time', new Date().toISOString());
    localStorage.setItem('quiz_completed', 'true');
    localStorage.setItem('quiz_taken', 'true');
    
    // Update state
    setQuizResults(sampleResults);
    setProgress(prev => ({
      ...prev,
      quizCompleted: 100
    }));
    
    // Trigger refresh
    setDataVersion(prev => prev + 1);
  };

  const formatTime = (date) => {
    if (!date) return 'Never';
    return date.toLocaleTimeString();
  };

  // Get personality type from quiz results
  const getPersonalityType = () => {
    return quizResults?.personalityType || 'Not assessed yet';
  };

  // Get top career recommendation
  const getTopCareerRecommendation = () => {
    if (!quizResults?.careerRecommendations?.[0]) return null;
    return quizResults.careerRecommendations[0];
  };

  if (!user) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to view your progress.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            Loading your progress...
          </div>
        </div>
      </div>
    );
  }

  const progressLevel = getOverallProgress() >= 80 ? 'Advanced' : 
                       getOverallProgress() >= 60 ? 'Intermediate' : 
                       getOverallProgress() >= 40 ? 'Beginner' : 'Getting Started';

  const topCareer = getTopCareerRecommendation();
  const personalityType = getPersonalityType();

  return (
    <div className="progress-container">
      <div className="container">
        <div className="progress-header">
          <div className="header-content">
            <div>
              <h1>📊 Your Career Progress</h1>
              <p>Track your career development journey</p>
            </div>
            <div className="header-actions">
              <button 
                onClick={refreshProgress}
                className="btn btn-secondary refresh-btn"
                disabled={loading}
              >
                {loading ? '🔄 Updating...' : '🔄 Refresh Progress'}
              </button>
            </div>
          </div>
          {lastUpdated && (
            <div className="last-updated">
              Last updated: {formatTime(lastUpdated)}
            </div>
          )}
        </div>

        {/* Debug Panel - Remove in production */}
        <div className="debug-panel">
          <strong>Debug Info:</strong> 
          <div>Quiz Status: {progress.quizCompleted}% complete</div>
          <div>Has Quiz Results: {quizResults ? 'Yes' : 'No'}</div>
          <div>Quiz Sources Checked: API, UserData, LocalStorage</div>
          <button 
            onClick={simulateQuizCompletion}
            className="btn btn-small debug-btn"
          >
            🧪 Simulate Quiz Completion (Test)
          </button>
        </div>

        {/* Quiz Results Summary - Show only if quiz is actually completed */}
        {progress.quizCompleted === 100 && quizResults && (
          <div className="quiz-results-summary">
            <div className="results-header">
              <h2>🎯 Your Career Assessment Results</h2>
              <span className="compatibility-score">
                {quizResults.compatibilityScore || 85}% Match
              </span>
            </div>
            
            <div className="results-grid">
              <div className="result-card personality-card">
                <h4>Personality Type</h4>
                <div className="personality-type">{personalityType}</div>
                <p>Your natural working style and preferences</p>
              </div>

              {topCareer && (
                <div className="result-card career-card">
                  <h4>Top Career Match</h4>
                  <div className="career-role">{topCareer.role}</div>
                  <div className="career-field">{topCareer.field}</div>
                  <div className="match-percentage">{topCareer.matchPercentage}% Match</div>
                </div>
              )}
            </div>

            <div className="results-actions">
              <button 
                onClick={() => window.location.href = '/quiz-results'}
                className="btn btn-primary"
              >
                View Detailed Results
              </button>
            </div>
          </div>
        )}

        {/* Overall Progress */}
        <div className="overall-progress-section">
          <div className="progress-card">
            <h2>Overall Career Progress</h2>
            <div className="progress-stats">
              <div className="stat">
                <span className="stat-value">{Math.round(progress.quizCompleted)}%</span>
                <span className="stat-label">Assessment</span>
              </div>
              <div className="stat">
                <span className="stat-value">{Math.round(progress.profileCompleted)}%</span>
                <span className="stat-label">Profile</span>
              </div>
              <div className="stat">
                <span className="stat-value">{Math.round(progress.mentorsConnected)}%</span>
                <span className="stat-label">Mentors</span>
              </div>
            </div>
            
            <div className="progress-circle-large">
              <div 
                className="circle" 
                style={{ 
                  background: `conic-gradient(${getProgressColor(getOverallProgress())} ${getOverallProgress() * 3.6}deg, #e2e8f0 0deg)` 
                }}
              >
                <span className="progress-value">{getOverallProgress()}%</span>
              </div>
            </div>
            <div className="progress-level">
              <span className="level-badge">{progressLevel}</span>
            </div>
          </div>
        </div>

        {/* Detailed Progress */}
        <div className="detailed-progress">
          <h3>Detailed Progress Breakdown</h3>
          
          <div className="progress-grid">
            {/* Career Assessment */}
            <div className="progress-category">
              <div className="category-header">
                <h4>Career Assessment</h4>
                <span className="category-percentage">{Math.round(progress.quizCompleted)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.quizCompleted}%`,
                    backgroundColor: getProgressColor(progress.quizCompleted)
                  }}
                ></div>
              </div>
              <div className="category-actions">
                {progress.quizCompleted === 100 ? (
                  <div className="completed-section">
                    <span className="completed-text">✅ Assessment Complete</span>
                    {quizResults && (
                      <div className="quiz-summary">
                        <small>
                          Type: {personalityType} • 
                          Match: {quizResults.compatibilityScore || 85}%
                        </small>
                      </div>
                    )}
                    <button 
                      onClick={() => window.location.href = '/quiz-results'}
                      className="btn btn-secondary btn-small"
                    >
                      View Results
                    </button>
                  </div>
                ) : (
                  <div className="incomplete-section">
                    <span className="incomplete-text">Take the career quiz to discover your path</span>
                    <button 
                      onClick={() => window.location.href = '/quiz'}
                      className="btn btn-primary btn-small"
                    >
                      Start Quiz
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* Profile Completion */}
            <div className="progress-category">
              <div className="category-header">
                <h4>Profile Completion</h4>
                <span className="category-percentage">{Math.round(progress.profileCompleted)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.profileCompleted}%`,
                    backgroundColor: getProgressColor(progress.profileCompleted)
                  }}
                ></div>
              </div>
              <div className="category-actions">
                {progress.profileCompleted === 100 ? (
                  <span className="completed-text">✅ Profile Complete</span>
                ) : (
                  <button 
                    onClick={() => window.location.href = '/profile'}
                    className="btn btn-secondary btn-small"
                  >
                    Complete Profile
                  </button>
                )}
              </div>
            </div>

            {/* Mentor Connections */}
            <div className="progress-category">
              <div className="category-header">
                <h4>Mentor Connections</h4>
                <span className="category-percentage">{Math.round(progress.mentorsConnected)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.mentorsConnected}%`,
                    backgroundColor: getProgressColor(progress.mentorsConnected)
                  }}
                ></div>
              </div>
              <div className="category-actions">
                <button 
                  onClick={() => window.location.href = '/mentors'}
                  className="btn btn-primary btn-small"
                >
                  {progress.mentorsConnected > 0 ? 'Find More Mentors' : 'Connect with Mentors'}
                </button>
              </div>
            </div>

            {/* Skills Development */}
            <div className="progress-category">
              <div className="category-header">
                <h4>Skills Development</h4>
                <span className="category-percentage">{Math.round(progress.skillsAdded)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.skillsAdded}%`,
                    backgroundColor: getProgressColor(progress.skillsAdded)
                  }}
                ></div>
              </div>
              <div className="category-actions">
                <button 
                  onClick={() => window.location.href = '/profile'}
                  className="btn btn-secondary btn-small"
                >
                  Manage Skills
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Progress Tips */}
        <div className="progress-tips">
          <h3>💡 Next Steps</h3>
          <div className="tips-grid">
            {progress.quizCompleted === 0 && (
              <div className="tip-card">
                <h4>Take Career Assessment</h4>
                <p>Complete the career quiz to discover your ideal career path and get personalized recommendations.</p>
                <button 
                  onClick={() => window.location.href = '/quiz'}
                  className="btn btn-primary btn-small"
                >
                  Start Quiz
                </button>
              </div>
            )}
            {progress.profileCompleted < 100 && (
              <div className="tip-card">
                <h4>Complete Your Profile</h4>
                <p>A complete profile helps us provide better career matches and mentor recommendations.</p>
                <button 
                  onClick={() => window.location.href = '/profile'}
                  className="btn btn-secondary btn-small"
                >
                  Complete Profile
                </button>
              </div>
            )}
            {progress.mentorsConnected === 0 && (
              <div className="tip-card">
                <h4>Connect with Mentors</h4>
                <p>Find mentors in your desired field to get guidance and accelerate your career growth.</p>
                <button 
                  onClick={() => window.location.href = '/mentors'}
                  className="btn btn-primary btn-small"
                >
                  Find Mentors
                </button>
              </div>
            )}
            {progress.quizCompleted === 100 && quizResults && (
              <div className="tip-card">
                <h4>Explore Your Career Matches</h4>
                <p>Based on your assessment, explore detailed career recommendations and learning paths.</p>
                <button 
                  onClick={() => window.location.href = '/career-recommendations'}
                  className="btn btn-primary btn-small"
                >
                  View Careers
                </button>
              </div>
            )}
            {progress.quizCompleted === 100 && progress.profileCompleted === 100 && (
              <div className="tip-card">
                <h4>Great Progress! 🎉</h4>
                <p>You've completed the initial setup. Now focus on connecting with mentors and developing your skills.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Progress;
